[
  {
    "id": "6",
    "original_query": "select s_acctbal, s_name, n_name, p_partkey, p_mfgr, s_address, s_phone, s_comment from part, supplier, partsupp, nation, region where p_partkey = ps_partkey and s_suppkey = ps_suppkey and p_size = 3 and p_type like '%NICKEL' and s_nationkey = n_nationkey and n_regionkey = r_regionkey and r_name = 'AMERICA' and ps_supplycost = ( select min(ps_supplycost) from partsupp, supplier, nation, region where p_partkey = ps_partkey and s_suppkey = ps_suppkey and s_nationkey = n_nationkey and n_regionkey = r_regionkey and r_name = 'AMERICA' ) order by s_acctbal desc, n_name, s_name, p_partkey limit 100;",
    "rewritten_query": "WITH asia_suppliers AS (\n    SELECT DISTINCT s.s_suppkey, s.s_acctbal, s.s_name, \n           s.s_address, s.s_phone, s.s_comment, \n           n.n_name, s.s_nationkey\n    FROM supplier s\n    JOIN nation n ON s.s_nationkey = n.n_nationkey\n    JOIN region r ON n.n_regionkey = r.r_regionkey\n    WHERE r.r_name = 'ASIA'\n),\nmin_supply AS (\n    SELECT ps_partkey, MIN(ps_supplycost) AS min_supplycost\n    FROM partsupp ps\n    JOIN asia_suppliers a ON ps.ps_suppkey = a.s_suppkey\n    GROUP BY ps_partkey\n)\nSELECT \n    a.s_acctbal,\n    a.s_name,\n    a.n_name,\n    p.p_partkey,\n    p.p_mfgr,\n    a.s_address,\n    a.s_phone,\n    a.s_comment\nFROM part p\nJOIN partsupp ps ON p.p_partkey = ps.ps_partkey\nJOIN asia_suppliers a ON ps.ps_suppkey = a.s_suppkey\nJOIN min_supply ms ON ps.ps_partkey = ms.ps_partkey \n    AND ps.ps_supplycost = ms.min_supplycost\nWHERE p.p_size = 46\n    AND p.p_type LIKE '%NICKEL'\nORDER BY s_acctbal DESC, n_name, s_name, p_partkey\nLIMIT 100;"
  },
  {
    "id": "7",
    "original_query": "select l_orderkey, sum(l_extendedprice * (1 - l_discount)) as revenue, o_orderdate, o_shippriority from customer, orders, lineitem where c_mktsegment = 'MACHINERY' and c_custkey = o_custkey and l_orderkey = o_orderkey and o_orderdate < date '1995-03-20' and l_shipdate > date '1995-03-20' group by l_orderkey, o_orderdate, o_shippriority order by revenue desc, o_orderdate limit 10;",
    "rewritten_query": "WITH filtered_parts AS (\n    SELECT *\n    FROM part\n    WHERE p_size = 3\n    AND p_type LIKE '%NICKEL'\n), min_supply AS (\n    SELECT \n        ps.ps_partkey,\n        MIN(ps.ps_supplycost) AS min_cost\n    FROM partsupp ps\n    INNER JOIN supplier s ON s.s_suppkey = ps.ps_suppkey\n    INNER JOIN nation n ON n.n_nationkey = s.s_nationkey\n    INNER JOIN region r ON r.r_regionkey = n.n_regionkey\n    WHERE r.r_name = 'AMERICA'\n    GROUP BY ps.ps_partkey\n)\nSELECT \n    s.s_acctbal,\n    s.s_name,\n    n.n_name,\n    p.p_partkey,\n    p.p_mfgr,\n    s.s_address,\n    s.s_phone,\n    s.s_comment\nFROM filtered_parts p\nINNER JOIN partsupp ps ON p.p_partkey = ps.ps_partkey\nINNER JOIN supplier s ON s.s_suppkey = ps.ps_suppkey\nINNER JOIN nation n ON n.n_nationkey = s.s_nationkey\nINNER JOIN min_supply ms ON ps.ps_partkey = ms.ps_partkey \n    AND ps.ps_supplycost = ms.min_cost\nORDER BY \n    s.s_acctbal DESC,\n    n.n_name,\n    s.s_name,\n    p.p_partkey\nLIMIT 100;"
  },
  {
    "id": "8",
    "original_query": "select l_orderkey, sum(l_extendedprice * (1 - l_discount)) as revenue, o_orderdate, o_shippriority from customer, orders, lineitem where c_mktsegment = 'MACHINERY' and c_custkey = o_custkey and l_orderkey = o_orderkey and o_orderdate < date '1995-03-14' and l_shipdate > date '1995-03-14' group by l_orderkey, o_orderdate, o_shippriority order by revenue desc, o_orderdate limit 10;",
    "rewritten_query": "WITH lineitem_filtered AS (\n    -- Pre-filter lineitem before aggregation\n    SELECT l_orderkey,\n           SUM(l_extendedprice * (1 - l_discount)) AS revenue\n    FROM lineitem\n    WHERE l_shipdate > DATE '1995-03-20'\n    GROUP BY l_orderkey\n)\nSELECT l.l_orderkey, \n       l.revenue, \n       o.o_orderdate, \n       o.o_shippriority \nFROM orders o\n-- Join with pre-filtered customer data first to reduce rows early\nINNER JOIN customer c \n    ON o.o_custkey = c.c_custkey \n    AND c.c_mktsegment = 'MACHINERY'\n-- Then join with aggregated lineitem data\nINNER JOIN lineitem_filtered l \n    ON o.o_orderkey = l.l_orderkey\nWHERE o.o_orderdate < DATE '1995-03-20'\nORDER BY l.revenue DESC, o.o_orderdate \nLIMIT 10;"
  },
  {
    "id": "9",
    "original_query": "select l_orderkey, sum(l_extendedprice * (1 - l_discount)) as revenue, o_orderdate, o_shippriority from customer, orders, lineitem where c_mktsegment = 'BUILDING' and c_custkey = o_custkey and l_orderkey = o_orderkey and o_orderdate < date '1995-03-08' and l_shipdate > date '1995-03-08' group by l_orderkey, o_orderdate, o_shippriority order by revenue desc, o_orderdate limit 10;",
    "rewritten_query": "WITH filtered_orders AS (\n    SELECT o_orderkey, o_custkey, o_orderdate, o_shippriority\n    FROM orders\n    WHERE o_orderdate < DATE '1995-03-14'\n),\nfiltered_lineitem AS (\n    SELECT \n        l_orderkey, \n        SUM(l_extendedprice * (1 - l_discount)) AS revenue_lineitem\n    FROM lineitem\n    WHERE l_shipdate > DATE '1995-03-14'\n    GROUP BY l_orderkey\n)\nSELECT \n    l.l_orderkey,\n    l.revenue_lineitem AS revenue,\n    o.o_orderdate,\n    o.o_shippriority\nFROM filtered_orders o\nINNER JOIN customer c \n    ON c.c_custkey = o.o_custkey\n    AND c.c_mktsegment = 'MACHINERY'\nINNER JOIN filtered_lineitem l \n    ON o.o_orderkey = l.l_orderkey\nORDER BY revenue DESC, o.o_orderdate\nLIMIT 10;"
  },
  {
    "id": "10",
    "original_query": "select o_orderpriority, count(*) as order_count from orders where o_orderdate >= date '1996-01-01' and o_orderdate < date '1996-01-01' + interval '3' month and exists ( select * from lineitem where l_orderkey = o_orderkey and l_commitdate < l_receiptdate ) group by o_orderpriority order by o_orderpriority;",
    "rewritten_query": "WITH revenue_calc AS (\n    SELECT \n        li.l_orderkey, \n        SUM(li.l_extendedprice * (1 - li.l_discount)) AS revenue, \n        ord.o_orderdate, \n        ord.o_shippriority \n    FROM \n        customer cust\n        INNER JOIN orders ord \n            ON cust.c_custkey = ord.o_custkey\n        INNER JOIN lineitem li \n            ON ord.o_orderkey = li.l_orderkey\n    WHERE \n        cust.c_mktsegment = 'BUILDING'\n        AND ord.o_orderdate < DATE '1995-03-08'\n        AND li.l_shipdate > DATE '1995-03-08'\n    GROUP BY \n        li.l_orderkey, \n        ord.o_orderdate, \n        ord.o_shippriority\n)\nSELECT \n    l_orderkey,\n    revenue,\n    o_orderdate,\n    o_shippriority\nFROM \n    revenue_calc\nORDER BY \n    revenue DESC, \n    o_orderdate \nLIMIT 10;"
  }
]
